using System.Collections.Specialized;
using Quartz;
using Quartz.Impl;
using Quartz.Spi;
public static class Program
{
    public static async Task<int> Main()
    {
        var properties = new NameValueCollection
        {
            ["quartz.scheduler.instanceName"] = "AsyncLocalRepro",
            ["quartz.threadPool.type"] = typeof(UnsafeThreadPool).AssemblyQualifiedName,
            ["quartz.jobStore.type"] = typeof(Quartz.Simpl.RAMJobStore).AssemblyQualifiedName
        };
        var scheduler = await new StdSchedulerFactory(properties).GetScheduler();
        scheduler.JobFactory = new AmbientJobFactory();
        var job = JobBuilder.Create<AmbientJob>()
            .WithIdentity("ambient-job")
            .UsingJobData("tenantId", "001")
            .Build();
        var trigger = TriggerBuilder.Create()
            .WithIdentity("ambient-trigger")
            .StartNow()
            .Build();
        await scheduler.ScheduleJob(job, trigger);
        await scheduler.Start();
        var completed = await Task.WhenAny(Ambient.Result.Task, Task.Delay(TimeSpan.FromSeconds(10)));
        await scheduler.Shutdown(waitForJobsToComplete: true);
        if (completed != Ambient.Result.Task)
        {
            Console.Error.WriteLine("Timed out waiting for job execution.");
            return 2;
        }
        var actual = await Ambient.Result.Task;
        Console.WriteLine($"AsyncLocal tenant observed by job: {actual ?? "<null>"}");
        return actual == "001" ? 0 : 1;
    }
}
static class Ambient
{
    public static readonly AsyncLocal<string?> Tenant = new();
    public static readonly TaskCompletionSource<string?> Result = new(TaskCreationOptions.RunContinuationsAsynchronously);
}
public sealed class UnsafeThreadPool : IThreadPool
{
    private int running;
    public int PoolSize => 1;
    public string InstanceId { private get; set; } = "";
    public string InstanceName { private get; set; } = "";
    public int BlockForAvailableThreads() => 1;
    public void Initialize() { }
    public void Shutdown(bool waitForJobsToComplete = true)
    {
        if (!waitForJobsToComplete) return;
        var sw = new SpinWait();
        while (Volatile.Read(ref running) > 0) sw.SpinOnce();
    }
    public bool RunInThread(Func<Task> runnable)
    {
        Interlocked.Increment(ref running);
        ThreadPool.UnsafeQueueUserWorkItem(async _ =>
        {
            try { await runnable(); }
            finally { Interlocked.Decrement(ref running); }
        }, null);
        return true;
    }
}
sealed class AmbientJobFactory : IJobFactory
{
    public IJob NewJob(TriggerFiredBundle bundle, IScheduler scheduler)
    {
        Ambient.Tenant.Value = bundle.JobDetail.JobDataMap.GetString("tenantId");
        return new AmbientJob();
    }
    public ValueTask ReturnJob(IJob job) => default;
}
sealed class AmbientJob : IJob
{
    public ValueTask Execute(IJobExecutionContext context)
    {
        Ambient.Result.TrySetResult(Ambient.Tenant.Value);
        return default;
    }
}
