        qs!.AddInternalSchedulerListener(this);

        IJob job = jec!.jobInstance;

        try
        {
            IOperableTrigger trigger = (IOperableTrigger) jec.Trigger;
            IJobDetail jobDetail = jec.JobDetail;
            do
            {
                JobExecutionException? jobExEx = null;

