using System.Collections.Concurrent;
using System.Collections.Specialized;
using Quartz;
using Quartz.Impl;
using Quartz.Spi;

public static class Program
{
    public static async Task<int> Main()
    {
        var properties = new NameValueCollection
        {
            ["quartz.scheduler.instanceName"] = "AsyncLocalRepro",
            ["quartz.threadPool.type"] = typeof(UnsafeThreadPool).AssemblyQualifiedName,
            ["quartz.jobStore.type"] = typeof(Quartz.Simpl.RAMJobStore).AssemblyQualifiedName
        };

        var scheduler = await new StdSchedulerFactory(properties).GetScheduler();
        scheduler.JobFactory = new AmbientJobFactory();

        await ScheduleTenantJob(scheduler, "ambient-job-001", "001");
        await ScheduleTenantJob(scheduler, "ambient-job-002", "002");
        await scheduler.Start();

        var completed = await Task.WhenAny(Ambient.AllResults.Task, Task.Delay(TimeSpan.FromSeconds(10)));
        await scheduler.Shutdown(waitForJobsToComplete: true);

        if (completed != Ambient.AllResults.Task)
        {
            Console.Error.WriteLine("Timed out waiting for job execution.");
            return 2;
        }

        var first = Ambient.Results.GetValueOrDefault("ambient-job-001");
        var second = Ambient.Results.GetValueOrDefault("ambient-job-002");
        var parent = Ambient.Tenant.Value;
        Console.WriteLine($"tenant-001 job observed: {first ?? "<null>"}");
        Console.WriteLine($"tenant-002 job observed: {second ?? "<null>"}");
        Console.WriteLine($"parent context after jobs: {parent ?? "<null>"}");
        return first == "001" && second == "002" && parent is null ? 0 : 1;
    }

    private static Task ScheduleTenantJob(IScheduler scheduler, string name, string tenantId)
    {
        var job = JobBuilder.Create<AmbientJob>()
            .WithIdentity(name)
            .UsingJobData("tenantId", tenantId)
            .Build();
        var trigger = TriggerBuilder.Create()
            .WithIdentity($"{name}-trigger")
            .StartNow()
            .Build();
        return scheduler.ScheduleJob(job, trigger);
    }
}

static class Ambient
{
    public static readonly AsyncLocal<string?> Tenant = new();
    public static readonly ConcurrentDictionary<string, string?> Results = new();
    public static readonly TaskCompletionSource<bool> AllResults = new(TaskCreationOptions.RunContinuationsAsynchronously);

    public static void AddResult(string jobName, string? tenant)
    {
        Results[jobName] = tenant;
        if (Results.Count == 2)
        {
            AllResults.TrySetResult(true);
        }
    }
}

public sealed class UnsafeThreadPool : IThreadPool
{
    private int running;
    public int PoolSize => 2;
    public string InstanceId { private get; set; } = "";
    public string InstanceName { private get; set; } = "";
    public int BlockForAvailableThreads() => 2;
    public void Initialize() { }
    public void Shutdown(bool waitForJobsToComplete = true)
    {
        if (!waitForJobsToComplete) return;
        var sw = new SpinWait();
        while (Volatile.Read(ref running) > 0) sw.SpinOnce();
    }
    public bool RunInThread(Func<Task> runnable)
    {
        Interlocked.Increment(ref running);
        ThreadPool.UnsafeQueueUserWorkItem(async _ =>
        {
            try { await runnable(); }
            finally { Interlocked.Decrement(ref running); }
        }, null);
        return true;
    }
}

